def msg = String.valueOf(ctx.message);
if (msg == null || msg == 'null') return;

// Split on first newline
def lines = /\n/.split(msg, 2);

// Build complete message with logger info
def completeMessage = lines[0];
if (ctx.spark?.class != null && ctx.line_number != null) {
    completeMessage = ctx.spark.class + ":" + ctx.line_number + " - " + completeMessage;
}

// First line becomes msg.message (with logger info)
if (ctx.msg == null) { ctx.msg = [:]; }
ctx.msg.message = completeMessage;

// Remaining lines become msg.stack_trace (if present and looks like stack trace)
if (lines.length > 1) {
    def remainder = lines[1];
    if (remainder.length() > 20 && (remainder.contains('at ') || remainder.contains('Exception') || remainder.contains('Error') || remainder.contains('Caused by'))) {
        // HTML escape the stack trace to prevent Dynamic Text panel from auto-wrapping in <pre>
        def escaped = remainder
            .replace('&', '&amp;')
            .replace('<', '&lt;')
            .replace('>', '&gt;')
            .replace('"', '&quot;')
            .replace("'", '&#39;');
        ctx.msg.stack_trace = escaped;
    }
}
